            {
              "instruction": "Complete the sentence about a key disadvantage of the Bus topology, using terms from the video and learning cards.",
              "codeTemplate": "A major disadvantage of the Bus topology is that if the _____ fails, the entire _____ goes down.",
              "options": [
                "network",
                "device",
                "backbone",
                "switch"
              ],
              "correctAnswer": "backbone,network",
              "explanation": "If the backbone fails in a bus topology, the entire network goes down."
            },
            {
              "instruction": "Fill in the blanks to compare Bus and Star topologies, using terms from the flashcards.",
              "codeTemplate": "Unlike the Star topology that uses a central _____, the Bus topology uses a central _____. ",
              "options": [
                "cable",
                "hub",
                "switch",
                "router"
              ],
              "correctAnswer": "hub,cable",
              "explanation": "Star topology uses a central hub, while Bus topology uses a central cable."
            }
          ]
        }
      }
